class Solution:
    def minimumCost(self, nums: List[int]) -> int:
        n = len(nums)
        min_total = float('inf')

        # Iterate over all possible split points for the first subarray
        for i in range(1, n - 1):
            # Iterate over all possible split points for the second subarray
            for j in range(i + 1, n):
                cost = nums[0] + nums[i] + nums[j]
                min_total = min(min_total, cost)

        return min_total
